package main

import (
	"github.com/pocketbase/pocketbase/core"
	"github.com/pocketbase/pocketbase/migrations"
)

func init() {
	migrations.Register(func(app core.App) error {
		orgCollection, err := app.FindCollectionByNameOrId("organizations")
		if err != nil {
			return err
		}

		if orgCollection.Fields.GetByName("logo") == nil {
			orgCollection.Fields.Add(&core.FileField{
				Name:      "logo",
				MaxSelect: 1,
				MaxSize:   5 << 20,
				MimeTypes: []string{"image/jpeg", "image/png", "image/svg+xml", "image/webp"},
				Thumbs:    []string{"64x64f", "128x128f"},
			})
			if err := app.Save(orgCollection); err != nil {
				return err
			}
		}

		if _, err := app.FindCollectionByNameOrId("organization_invites"); err == nil {
			return nil
		}

		invitesCollection := core.NewBaseCollection("organization_invites")
		invitesCollection.Fields.Add(
			&core.RelationField{
				Name:         "organization",
				CollectionId: orgCollection.Id,
				MaxSelect:    1,
				Required:     true,
			},
			&core.EmailField{
				Name:     "invited_email",
				Required: true,
			},
			&core.RelationField{
				Name:         "invited_user",
				CollectionId: "_pb_users_auth_",
				MaxSelect:    1,
				Required:     true,
			},
			&core.RelationField{
				Name:         "invited_by",
				CollectionId: "_pb_users_auth_",
				MaxSelect:    1,
				Required:     true,
			},
			&core.TextField{
				Name:     "token_hash",
				Required: true,
			},
			&core.SelectField{
				Name:      "status",
				Required:  true,
				MaxSelect: 1,
				Values: []string{
					"pending",
					"accepted",
					"revoked",
					"expired",
				},
			},
			&core.DateField{
				Name:     "expires_at",
				Required: true,
			},
			&core.DateField{
				Name: "accepted_at",
			},
			&core.RelationField{
				Name:         "accepted_by",
				CollectionId: "_pb_users_auth_",
				MaxSelect:    1,
			},
			&core.AutodateField{
				Name:     "created",
				OnCreate: true,
			},
			&core.AutodateField{
				Name:     "updated",
				OnCreate: true,
				OnUpdate: true,
			},
		)

		return app.Save(invitesCollection)
	}, func(app core.App) error {
		if invitesCollection, err := app.FindCollectionByNameOrId("organization_invites"); err == nil {
			if err := app.Delete(invitesCollection); err != nil {
				return err
			}
		}

		orgCollection, err := app.FindCollectionByNameOrId("organizations")
		if err != nil {
			return err
		}

		orgCollection.Fields.RemoveByName("logo")
		return app.Save(orgCollection)
	}, "1709000000_organization_invites.go")
}
